#include <iostream>
using namespace std;

int main() {
    int n;
    cin >> n;

    int prev;
    cin >> prev;

    int count = 0;
    for (int i = 1; i < n; i++) {
        int cur;
        cin >> cur;
        if (cur > prev) {
            count++;
        }
        prev = cur;
    }

    cout << count << endl;
    return 0;
}
